import { useEffect, useMemo, useState } from "react";
import api from "../services/api";
import "./Dashboard.css";
import Navbar from "../components/Navbar";

function Dashboard() {
  const role = localStorage.getItem("role");

  const [items, setItems] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [showCart, setShowCart] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState("All");

  // ================= LOAD ITEMS =================
  useEffect(() => {
    fetchItems();
  }, []);

  const fetchItems = async () => {
    try {
      const res = await api.get("/items");
      setItems(res.data || []);
    } catch (err) {
      console.error("Error loading items:", err);
    }
  };

  // ================= SAFE ID =================
  const getId = (item) => item.id ?? item.itemId;

  // ================= CART =================
  const addToCart = (item) => {
    const id = getId(item);

    setCart((prev) => {
      const existing = prev.find((i) => getId(i) === id);

      if (existing) {
        return prev.map((i) =>
          getId(i) === id ? { ...i, qty: i.qty + 1 } : i
        );
      }

      return [...prev, { ...item, id, qty: 1 }];
    });
  };

  const increase = (id) => {
    setCart((prev) =>
      prev.map((i) =>
        getId(i) === id ? { ...i, qty: i.qty + 1 } : i
      )
    );
  };

  const decrease = (id) => {
    setCart((prev) =>
      prev
        .map((i) =>
          getId(i) === id ? { ...i, qty: i.qty - 1 } : i
        )
        .filter((i) => i.qty > 0)
    );
  };

  // ================= TOTAL =================
  const total = useMemo(() => {
    return cart.reduce(
      (sum, i) => sum + (Number(i.price) || 0) * (i.qty || 0),
      0
    );
  }, [cart]);

  // ================= FILTERED ITEMS =================
  const filteredItems = useMemo(() => {
    let data = items.filter((item) =>
      (item.name || "")
        .toLowerCase()
        .includes(search.toLowerCase())
    );

    if (selectedCategory !== "All") {
      data = data.filter(
        (item) => item.category === selectedCategory
      );
    }

    return data;
  }, [items, search, selectedCategory]);

  // ================= CATEGORIES (STABLE) =================
  const categories = useMemo(() => {
    const set = new Set(
      items.map((i) => i.category || "Other")
    );
    return ["All", ...set];
  }, [items]);

  // ================= ADMIN =================
  if (role === "ROLE_ADMIN") {
    return (
      <div>
        <Navbar />
        <div className="admin-container">
          <h2>🧑‍💼 Admin Dashboard</h2>
          <p>Use Admin Panel</p>
        </div>
      </div>
    );
  }

  // ================= USER DASHBOARD =================
  return (
    <div>
      <Navbar />

      {/* HEADER */}
      <div className="header">
        <h2>🛒 Grocery Store</h2>

        <input
          className="search"
          placeholder="Search products..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <button onClick={() => setShowCart((prev) => !prev)}>
          Cart ({cart.reduce((s, i) => s + i.qty, 0)})
        </button>
      </div>

      {/* CATEGORY BAR */}
      <div className="category-bar">
        {categories.map((cat) => (
          <button
            key={cat}
            className={selectedCategory === cat ? "active" : ""}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* PRODUCTS */}
      <div className="products">
        <div className="grid">
          {filteredItems.map((item) => (
            <div className="card" key={getId(item)}>
              <img
                src={item.image_url || item.imageUrl}
                alt={item.name}
              />

              <h4>{item.name}</h4>
              <p>₹ {item.price}</p>

              <button onClick={() => addToCart(item)}>
                Add to Cart
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* CART OVERLAY */}
      {showCart && (
        <div
          className="cart-overlay"
          onClick={() => setShowCart(false)}
        >
          <div
            className="cart-panel"
            onClick={(e) => e.stopPropagation()}
          >
            <h3>🛒 Your Cart</h3>

            {cart.length === 0 ? (
              <p>Cart is empty</p>
            ) : (
              cart.map((item) => (
                <div
                  className="cart-item"
                  key={getId(item)}
                >
                  <span>{item.name}</span>

                  <div>
                    <button
                      onClick={() => decrease(getId(item))}
                    >
                      -
                    </button>

                    {item.qty}

                    <button
                      onClick={() => increase(getId(item))}
                    >
                      +
                    </button>
                  </div>

                  <span>
                    ₹{item.price * item.qty}
                  </span>
                </div>
              ))
            )}

            <h3>Total: ₹{total}</h3>

            <button
              onClick={() => {
                alert("Order placed 🎉");
                setCart([]);
                setShowCart(false);
              }}
            >
              Checkout
            </button>

            <button onClick={() => setShowCart(false)}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
